import React from 'react';
import {
  Card,
  Stack,
  Text,
  Heading,
  Divider,
  Box
} from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

/**
 * Weather Card component displaying current weather metrics and a multi-day forecast.
 * Uses semantic design tokens for theme compatibility and high-density data presentation.
 */
export default function GeneratedComponent({
  city = "Tokyo",
  temperature = 28,
  condition = "Sunny",
  humidity = 45,
  windSpeed = 8,
  unit = "C",
  forecast = [
    { day: "Mon", icon: "☀️", high: 30, low: 22 },
    { day: "Tue", icon: "⛅", high: 27, low: 20 },
    { day: "Wed", icon: "☁️", high: 25, low: 19 },
    { day: "Thu", icon: "🌧️", high: 22, low: 18 },
    { day: "Fri", icon: "⛈️", high: 24, low: 20 }
  ]
}: Props) {
  return (
    <Card 
      padding={0} 
      shadow="md" 
      radius="xl" 
      border 
    >
      <Stack gap={0}>
        {/* Top Section: Hero Branding and Current Temperature */}
        <Box 
          padding={24} 
          background="linear-gradient(135deg, var(--ggui-color-primary-600, #0284c7), var(--ggui-color-primary-800, #075985))"
          style={{ borderRadius: 'var(--ggui-shape-radius-xl, 16px) var(--ggui-shape-radius-xl, 16px) 0 0' }}
        >
          <Stack gap={16}>
            <Stack direction="horizontal" justify="between" align="start">
              <Stack gap={2}>
                <Heading level={3} color="var(--ggui-color-primary-50, #f0f9ff)">
                  {city ?? 'Location'}
                </Heading>
                <Text color="var(--ggui-color-primary-100, #e0f2fe)" variant="label">
                  {condition ?? 'Current Condition'}
                </Text>
              </Stack>
              <Text size="3xl" aria-hidden="true">
                {condition?.toLowerCase().includes("sun") ? "☀️" : 
                 condition?.toLowerCase().includes("cloud") ? "☁️" : 
                 condition?.toLowerCase().includes("rain") ? "🌧️" : "⛅"}
              </Text>
            </Stack>

            <Stack direction="horizontal" align="end" gap={4}>
              <Heading 
                level={1} 
                color="var(--ggui-color-primary-50, #f0f9ff)"
                style={{ fontSize: 'var(--ggui-font-size-4xl, 36px)', lineHeight: 1 }}
              >
                {Math.round(temperature ?? 0)}
              </Heading>
              <Text 
                size="2xl" 
                weight="medium" 
                color="var(--ggui-color-primary-200, #bae6fd)"
                style={{ paddingBottom: 'var(--ggui-spacing-1, 4px)' }}
              >
                °{unit ?? 'C'}
              </Text>
            </Stack>
          </Stack>
        </Box>

        {/* Middle Section: Specific Weather Metrics */}
        <Box padding={24} background="var(--ggui-color-surface, #ffffff)">
          <Stack direction="horizontal" justify="between" align="center">
            <Stack align="center" gap={4} style={{ flex: 1 }}>
              <Text variant="caption" weight="semibold" color="var(--ggui-color-onSurfaceVariant, #52525b)">HUMIDITY</Text>
              <Text size="base" weight="bold" color="var(--ggui-color-onSurface, #18181b)">{humidity ?? 0}%</Text>
            </Stack>

            <Divider orientation="vertical" margin={16} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

            <Stack align="center" gap={4} style={{ flex: 1 }}>
              <Text variant="caption" weight="semibold" color="var(--ggui-color-onSurfaceVariant, #52525b)">WIND</Text>
              <Text size="base" weight="bold" color="var(--ggui-color-onSurface, #18181b)">{windSpeed ?? 0} km/h</Text>
            </Stack>
          </Stack>
        </Box>

        <Divider margin={0} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

        {/* Bottom Section: 5-Day Forecast Strip */}
        <Box 
          padding={20} 
          background="var(--ggui-color-surfaceVariant, #f4f4f5)" 
          style={{ borderRadius: '0 0 var(--ggui-shape-radius-xl, 16px) var(--ggui-shape-radius-xl, 16px)' }}
        >
          <Stack direction="horizontal" gap={12} justify="between">
            {(forecast ?? []).map((item, idx) => (
              <Stack key={idx} align="center" gap={8} style={{ flex: 1 }}>
                <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {item.day ?? 'Day'}
                </Text>
                <Text size="lg" aria-hidden="true">{item.icon ?? '☀️'}</Text>
                <Stack gap={0} align="center">
                  <Text variant="bodySmall" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                    {item.high ?? 0}°
                  </Text>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {item.low ?? 0}°
                  </Text>
                </Stack>
              </Stack>
            ))}
          </Stack>
        </Box>
      </Stack>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Text,
  Heading,
  Button,
  Input,
  TextArea,
  Checkbox,
  RadioGroup,
  Progress,
  Box,
  Divider,
  Spacer,
  Alert
} from '@ggui-ai/design/primitives';

interface Props {
  /** Available feature options for the checkbox step */
  featureOptions?: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels?: string[];
  /** Action callback for form submission */
  onSubmit?: (data: any) => void;
}

export default function GeneratedComponent({
  featureOptions = [
    "Dashboard Analytics",
    "Team Collaboration",
    "API Integration",
    "Custom Workflows",
    "Mobile App",
    "AI Assistance"
  ],
  satisfactionLabels = [
    "Very Unsatisfied",
    "Unsatisfied",
    "Neutral",
    "Satisfied",
    "Very Satisfied"
  ],
  onSubmit
}: Props) {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: '',
    features: [] as string[],
    comments: ''
  });
  const [errors, setErrors] = useState({
    name: '',
    email: ''
  });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitted, setSubmitted] = useState(false);

  const totalSteps = 4;

  const validateStep1 = () => {
    const newErrors = { name: '', email: '' };
    let isValid = true;

    if (!formData.name.trim()) {
      newErrors.name = 'Name is required';
      isValid = false;
    }

    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!formData.email.trim()) {
      newErrors.email = 'Email is required';
      isValid = false;
    } else if (!emailRegex.test(formData.email)) {
      newErrors.email = 'Please enter a valid email address';
      isValid = false;
    }

    setErrors(newErrors);
    return isValid;
  };

  const isNextDisabled = () => {
    if (step === 1) {
      return !formData.name || !formData.email || !!errors.name || !!errors.email;
    }
    if (step === 2) {
      return !formData.satisfaction;
    }
    return false;
  };

  const handleNext = () => {
    if (step === 1) {
      if (validateStep1()) setStep(2);
    } else if (step < 5) {
      setStep(prev => prev + 1);
    }
  };

  const handleBack = () => {
    setStep(prev => Math.max(1, prev - 1));
  };

  const handleFeatureToggle = (feature: string, checked: boolean) => {
    setFormData(prev => ({
      ...prev,
      features: checked 
        ? [...prev.features, feature]
        : prev.features.filter(f => f !== feature)
    }));
  };

  const handleSubmit = async () => {
    setIsSubmitting(true);
    try {
      const payload = {
        ...formData,
        satisfaction: parseInt(formData.satisfaction, 10)
      };
      if (onSubmit) {
        await onSubmit(payload);
      }
      setSubmitted(true);
    } catch (e) {
      console.error(e);
    } finally {
      setIsSubmitting(false);
    }
  };

  if (submitted) {
    return (
      <Container maxWidth="md" padding={24}>
        <Card shadow="md" padding={40} radius="xl">
          <Stack gap={24} align="center">
            <Box 
              padding={16} 
              borderRadius="full" 
              background="var(--ggui-color-success-100, #dcfce7)"
            >
              <Text color="var(--ggui-color-success-600, #16a34a)" size="4xl" weight="bold">✓</Text>
            </Box>
            <Heading level={2} align="center">Thank You!</Heading>
            <Text align="center" color="var(--ggui-color-onSurfaceVariant)">
              Your survey responses have been successfully recorded. We appreciate your feedback!
            </Text>
            <Button variant="primary" onClick={() => window.location.reload()}>
              Submit Another Response
            </Button>
          </Stack>
        </Card>
      </Container>
    );
  }

  return (
    <Container maxWidth="md" padding={24}>
      <Stack gap={24}>
        {step <= 4 && (
          <Stack gap={8}>
            <Stack direction="horizontal" justify="between" align="end">
              <Text variant="label" color="var(--ggui-color-primary-600)">
                Step {step} of {totalSteps}
              </Text>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                {Math.round((step / totalSteps) * 100)}% Complete
              </Text>
            </Stack>
            <Progress value={step} max={totalSteps} variant="default" size="sm" />
          </Stack>
        )}

        <Card shadow="lg" padding={32} radius="xl">
          {step === 1 && (
            <Stack gap={24}>
              <Stack gap={4}>
                <Heading level={3}>Personal Information</Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                  Let's start with some basic details.
                </Text>
              </Stack>
              <Stack gap={16}>
                <Input
                  label="Full Name"
                  required
                  placeholder="e.g. John Doe"
                  value={formData.name}
                  onChange={(val) => {
                    setFormData({ ...formData, name: val });
                    if (errors.name) setErrors({ ...errors, name: '' });
                  }}
                  error={errors.name}
                />
                <Input
                  label="Email Address"
                  type="email"
                  required
                  placeholder="john@example.com"
                  value={formData.email}
                  onChange={(val) => {
                    setFormData({ ...formData, email: val });
                    if (errors.email) setErrors({ ...errors, email: '' });
                  }}
                  error={errors.email}
                />
              </Stack>
            </Stack>
          )}

          {step === 2 && (
            <Stack gap={24}>
              <Stack gap={4}>
                <Heading level={3}>Overall Satisfaction</Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                  How would you rate your overall experience with our platform?
                </Text>
              </Stack>
              <RadioGroup
                label="Satisfaction Level"
                value={formData.satisfaction}
                onChange={(val) => setFormData({ ...formData, satisfaction: val })}
                options={satisfactionLabels.map((label, index) => ({
                  value: (index + 1).toString(),
                  label: label,
                  description: `Rating: ${index + 1}/5`
                }))}
              />
            </Stack>
          )}

          {step === 3 && (
            <Stack gap={24}>
              <Stack gap={4}>
                <Heading level={3}>Feature Interests</Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                  Which features are you most interested in? (Select all that apply)
                </Text>
              </Stack>
              <Box 
                padding={16} 
                borderRadius="md" 
                background="var(--ggui-color-surfaceVariant)"
                style={{ border: '1px solid var(--ggui-color-outlineVariant)' }}
              >
                <Stack gap={12}>
                  {featureOptions.map((option) => (
                    <Checkbox
                      key={option}
                      label={option}
                      checked={formData.features.includes(option)}
                      onChange={(checked) => handleFeatureToggle(option, checked)}
                    />
                  ))}
                </Stack>
              </Box>
            </Stack>
          )}

          {step === 4 && (
            <Stack gap={24}>
              <Stack gap={4}>
                <Heading level={3}>Additional Feedback</Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                  Anything else you'd like to share with us?
                </Text>
              </Stack>
              <TextArea
                label="Comments"
                placeholder="Your thoughts..."
                value={formData.comments}
                onChange={(val) => setFormData({ ...formData, comments: val })}
                maxLength={500}
                showCount
                rows={6}
              />
            </Stack>
          )}

          {step === 5 && (
            <Stack gap={24}>
              <Stack gap={4}>
                <Heading level={3}>Review Your Answers</Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                  Please check your responses before submitting.
                </Text>
              </Stack>

              <Stack gap={16}>
                <Box padding={16} borderRadius="lg" background="var(--ggui-color-surfaceVariant)">
                  <Stack gap={12}>
                    <Stack gap={2}>
                      <Text variant="label" size="xs" color="var(--ggui-color-primary-600)">NAME</Text>
                      <Text weight="medium">{formData.name}</Text>
                    </Stack>
                    <Divider margin={8} color="var(--ggui-color-outlineVariant)" />
                    <Stack gap={2}>
                      <Text variant="label" size="xs" color="var(--ggui-color-primary-600)">EMAIL</Text>
                      <Text weight="medium">{formData.email}</Text>
                    </Stack>
                    <Divider margin={8} color="var(--ggui-color-outlineVariant)" />
                    <Stack gap={2}>
                      <Text variant="label" size="xs" color="var(--ggui-color-primary-600)">SATISFACTION</Text>
                      <Text weight="medium">
                        {satisfactionLabels[parseInt(formData.satisfaction) - 1] ?? 'Not selected'} ({formData.satisfaction}/5)
                      </Text>
                    </Stack>
                    <Divider margin={8} color="var(--ggui-color-outlineVariant)" />
                    <Stack gap={2}>
                      <Text variant="label" size="xs" color="var(--ggui-color-primary-600)">INTERESTS</Text>
                      <Text weight="medium">
                        {formData.features.length > 0 ? formData.features.join(', ') : 'None selected'}
                      </Text>
                    </Stack>
                    {formData.comments && (
                      <>
                        <Divider margin={8} color="var(--ggui-color-outlineVariant)" />
                        <Stack gap={2}>
                          <Text variant="label" size="xs" color="var(--ggui-color-primary-600)">COMMENTS</Text>
                          <Text weight="medium">{formData.comments}</Text>
                        </Stack>
                      </>
                    )}
                  </Stack>
                </Box>
                <Alert variant="info" title="Ready to submit?">
                  Click the button below to send your responses. You can't change them after submitting.
                </Alert>
              </Stack>
            </Stack>
          )}

          <Spacer size={32} />

          <Stack direction="horizontal" justify="between">
            <Button 
              variant="ghost" 
              onClick={handleBack} 
              disabled={step === 1 || isSubmitting}
            >
              Back
            </Button>

            {step < 5 ? (
              <Button 
                variant="primary" 
                onClick={handleNext} 
                disabled={isNextDisabled()}
              >
                {step === 4 ? 'Review Summary' : 'Next'}
              </Button>
            ) : (
              <Button 
                variant="primary" 
                onClick={handleSubmit} 
                loading={isSubmitting}
              >
                Submit Survey
              </Button>
            )}
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Stack,
  Box,
  Card,
  Text,
  Heading,
  Button,
  Input,
  Select,
  Badge,
  Avatar,
  Icon,
  Container,
  Spacer,
  Divider,
} from '@ggui-ai/design/primitives';

interface Task {
  id?: string;
  title?: string;
  priority?: 'low' | 'medium' | 'high';
  assignee?: string;
  column?: string;
  dueDate?: string;
}

interface Column {
  id?: string;
  name?: string;
}

interface Props {
  /** Array of tasks with id, title, priority, assignee initials, column ID, and optional dueDate */
  tasks?: Task[];
  /** Column definitions */
  columns?: Column[];
  /** Callback for task updates */
  taskUpdate?: (payload: { action: string; taskId?: string; data: any }) => void;
}

export default function GeneratedComponent({
  tasks = [],
  columns = [
    { id: 'todo', name: 'To Do' },
    { id: 'in-progress', name: 'In Progress' },
    { id: 'done', name: 'Done' },
  ],
  taskUpdate,
}: Props) {
  const [localTasks, setLocalTasks] = useState<Task[]>(tasks);
  const [addingToColumn, setAddingToColumn] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editTitle, setEditTitle] = useState('');

  // Sync props to local state
  useEffect(() => {
    setLocalTasks(tasks);
  }, [tasks]);

  // Agent data stream listener
  useEffect(() => {
    const handleAgentData = (event: any) => {
      if (event.detail?.tasks) {
        setLocalTasks(event.detail.tasks);
      }
    };
    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  const totalTasks = localTasks.length;
  const completedTasks = localTasks.filter((t) => t.column === 'done').length;

  const handleAddTask = (columnId: string) => {
    if (!newTaskTitle.trim()) return;
    const newTask: Task = {
      id: Math.random().toString(36).substr(2, 9),
      title: newTaskTitle,
      priority: newTaskPriority,
      column: columnId,
      assignee: '??',
    };
    const updated = [...localTasks, newTask];
    setLocalTasks(updated);
    taskUpdate?.({ action: 'create', data: newTask });
    setNewTaskTitle('');
    setAddingToColumn(null);
  };

  const handleMoveTask = (taskId: string, newColumn: string) => {
    const updated = localTasks.map((t) => (t.id === taskId ? { ...t, column: newColumn } : t));
    setLocalTasks(updated);
    taskUpdate?.({ action: 'move', taskId, data: { column: newColumn } });
  };

  const handleUpdateTitle = (taskId: string) => {
    if (!editTitle.trim()) {
      setEditingTaskId(null);
      return;
    }
    const updated = localTasks.map((t) => (t.id === taskId ? { ...t, title: editTitle } : t));
    setLocalTasks(updated);
    taskUpdate?.({ action: 'edit', taskId, data: { title: editTitle } });
    setEditingTaskId(null);
  };

  const priorityVariant = (p?: string) => {
    switch (p) {
      case 'high': return 'error';
      case 'medium': return 'warning';
      case 'low': return 'info';
      default: return 'default';
    }
  };

  return (
    <Container maxWidth="full" padding={24}>
      <Stack gap={24}>
        {/* Summary Bar */}
        <Card padding={16} shadow="sm" radius="lg" border={true}>
          <Stack direction="horizontal" align="center" justify="between">
            <Stack direction="horizontal" gap={16} align="center">
              <Heading level={4} color="var(--ggui-color-onSurface, #18181b)">Project Board</Heading>
              <Divider orientation="vertical" margin={8} />
              <Stack direction="horizontal" gap={8}>
                <Badge variant="primary">{totalTasks} Total Tasks</Badge>
                <Badge variant="success">{completedTasks} Completed</Badge>
              </Stack>
            </Stack>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Status: Active
            </Text>
          </Stack>
        </Card>

        {/* Kanban Board */}
        <Stack direction="horizontal" gap={20} align="start" style={{ overflowX: 'auto', paddingBottom: 12 }}>
          {columns.map((col) => {
            const columnTasks = localTasks.filter((t) => t.column === col.id);
            return (
              <Box
                key={col.id}
                padding={12}
                borderRadius="var(--ggui-shape-radius-xl, 16px)"
                background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                style={{ minWidth: 320, flex: '0 0 320px', minHeight: '70vh' }}
              >
                <Stack gap={16}>
                  {/* Column Header */}
                  <Stack direction="horizontal" justify="between" align="center" paddingX={4}>
                    <Stack direction="horizontal" gap={8} align="center">
                      <Text weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                        {col.name ?? 'Untitled'}
                      </Text>
                      <Badge size="sm" pill={true} variant="secondary">
                        {columnTasks.length}
                      </Badge>
                    </Stack>
                    <Button variant="ghost" size="xs">
                      <Icon name="menu" size={16} />
                    </Button>
                  </Stack>

                  {/* Task List */}
                  <Stack gap={12}>
                    {columnTasks.map((task) => (
                      <Card
                        key={task.id}
                        padding={16}
                        shadow="sm"
                        radius="md"
                        border={true}
                        style={{ backgroundColor: 'var(--ggui-color-surface, #fafafa)' }}
                      >
                        <Stack gap={12}>
                          <Stack direction="horizontal" justify="between" align="start">
                            <Badge variant={priorityVariant(task.priority)} size="sm">
                              {task.priority?.toUpperCase() ?? 'MEDIUM'}
                            </Badge>
                            <Select
                              label="Move task"
                              size="sm"
                              value={task.column ?? ''}
                              onChange={(val) => handleMoveTask(task.id!, val)}
                              options={columns.map((c) => ({ value: c.id ?? '', label: `Move to ${c.name}` }))}
                              style={{ width: 'auto', border: 'none', background: 'transparent' }}
                            />
                          </Stack>

                          {editingTaskId === task.id ? (
                            <Input
                              label="Edit Task Title"
                              autoFocus
                              value={editTitle}
                              onChange={setEditTitle}
                              onBlur={() => handleUpdateTitle(task.id!)}
                              onKeyDown={(e) => e.key === 'Enter' && handleUpdateTitle(task.id!)}
                            />
                          ) : (
                            <Text
                              weight="medium"
                              color="var(--ggui-color-onSurface, #18181b)"
                              style={{ cursor: 'pointer' }}
                              onDoubleClick={() => {
                                setEditingTaskId(task.id!);
                                setEditTitle(task.title ?? '');
                              }}
                            >
                              {task.title ?? 'No Title'}
                            </Text>
                          )}

                          <Stack direction="horizontal" align="center" justify="between">
                            <Stack direction="horizontal" gap={6} align="center">
                              <Icon name="user" size={14} color="var(--ggui-color-neutral-500, #6b7280)" />
                              <Avatar name={task.assignee ?? 'Avatar'} size="xs" />
                            </Stack>
                            {task.dueDate && (
                              <Stack direction="horizontal" gap={4} align="center">
                                <Icon name="settings" size={12} color="var(--ggui-color-neutral-500, #6b7280)" />
                                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                                  {task.dueDate}
                                </Text>
                              </Stack>
                            )}
                          </Stack>
                        </Stack>
                      </Card>
                    ))}

                    {/* Add Task Form */}
                    {addingToColumn === col.id ? (
                      <Card padding={12} radius="md" border={true}>
                        <Stack gap={12}>
                          <Input
                            label="New Task Title"
                            placeholder="What needs to be done?"
                            value={newTaskTitle}
                            onChange={setNewTaskTitle}
                            size="sm"
                            autoFocus
                          />
                          <Select
                            label="Priority"
                            value={newTaskPriority}
                            onChange={(val) => setNewTaskPriority(val as any)}
                            size="sm"
                            options={[
                              { value: 'low', label: 'Low' },
                              { value: 'medium', label: 'Medium' },
                              { value: 'high', label: 'High' },
                            ]}
                          />
                          <Stack direction="horizontal" gap={8}>
                            <Button size="sm" onPress={() => handleAddTask(col.id!)}>Add</Button>
                            <Button variant="ghost" size="sm" onPress={() => setAddingToColumn(null)}>Cancel</Button>
                          </Stack>
                        </Stack>
                      </Card>
                    ) : (
                      <Button
                        variant="ghost"
                        fullWidth={true}
                        leftIcon={<Icon name="plus" size={16} />}
                        onPress={() => setAddingToColumn(col.id ?? null)}
                      >
                        Add Task
                      </Button>
                    )}
                  </Stack>
                </Stack>
              </Box>
            );
          })}
        </Stack>
      </Stack>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Container,
  Stack,
  Box,
  Text,
  Heading,
  Card,
  Input,
  Icon,
  Divider,
  Spacer
} from '@ggui-ai/design/primitives';

interface Element {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  /** Full periodic table element data */
  elements: Element[];
}

/**
 * Maps element categories to semantic design tokens
 */
const getCategoryColor = (category: string | undefined): string => {
  const cat = category?.toLowerCase() || '';
  if (cat.includes('alkali metal')) return 'var(--ggui-color-error-100, #fee2e2)';
  if (cat.includes('alkaline earth')) return 'var(--ggui-color-warning-100, #fef3c7)';
  if (cat.includes('noble gas')) return 'var(--ggui-color-info-100, #cffafe)';
  if (cat.includes('halogen')) return 'var(--ggui-color-primary-100, #e0f2fe)';
  if (cat.includes('metalloid')) return 'var(--ggui-color-success-100, #dcfce7)';
  if (cat.includes('nonmetal')) return 'var(--ggui-color-primary-50, #f0f9ff)';
  if (cat.includes('transition metal')) return 'var(--ggui-color-neutral-100, #f3f4f6)';
  if (cat.includes('post-transition')) return 'var(--ggui-color-neutral-200, #e5e7eb)';
  if (cat.includes('lanthanide')) return 'var(--ggui-color-primary-200, #bae6fd)';
  if (cat.includes('actinide')) return 'var(--ggui-color-primary-300, #7dd3fc)';
  return 'var(--ggui-color-surfaceVariant, #f4f4f5)';
};

const getCategoryBorder = (category: string | undefined): string => {
  const cat = category?.toLowerCase() || '';
  if (cat.includes('alkali metal')) return 'var(--ggui-color-error-500, #ef4444)';
  if (cat.includes('alkaline earth')) return 'var(--ggui-color-warning-500, #f59e0b)';
  if (cat.includes('noble gas')) return 'var(--ggui-color-info-500, #06b6d4)';
  if (cat.includes('halogen')) return 'var(--ggui-color-primary-500, #0ea5e9)';
  if (cat.includes('metalloid')) return 'var(--ggui-color-success-500, #22c55e)';
  if (cat.includes('transition metal')) return 'var(--ggui-color-neutral-400, #9ca3af)';
  return 'var(--ggui-color-outline, #d4d4d8)';
};

export default function GeneratedComponent({ elements = [] }: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<Element | null>(null);

  const filteredElements = useMemo(() => {
    if (!searchQuery) return elements;
    const query = searchQuery.toLowerCase();
    return elements.filter(
      (el) =>
        el.name?.toLowerCase().includes(query) ||
        el.symbol?.toLowerCase().includes(query) ||
        el.atomicNumber?.toString() === query
    );
  }, [elements, searchQuery]);

  const categories = [
    { label: 'Alkali Metal', cat: 'alkali metal' },
    { label: 'Alkaline Earth', cat: 'alkaline earth' },
    { label: 'Transition Metal', cat: 'transition metal' },
    { label: 'Post-transition', cat: 'post-transition' },
    { label: 'Metalloid', cat: 'metalloid' },
    { label: 'Nonmetal', cat: 'nonmetal' },
    { label: 'Halogen', cat: 'halogen' },
    { label: 'Noble Gas', cat: 'noble gas' },
    { label: 'Lanthanide', cat: 'lanthanide' },
    { label: 'Actinide', cat: 'actinide' },
  ];

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap={24}>
        <Stack gap={8}>
          <Heading level={1}>Periodic Table of Elements</Heading>
          <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Explore the building blocks of the universe. Click an element for details.
          </Text>
        </Stack>

        <Card shadow="sm" padding={16}>
          <Input
            label="Search Elements"
            placeholder="Search by name, symbol, or number..."
            value={searchQuery}
            onChange={setSearchQuery}
          />
        </Card>

        <Stack direction="horizontal" gap={12} wrap justify="center">
          {categories.map((c) => (
            <Stack key={c.label} direction="horizontal" gap={6} align="center">
              <Box
                width={16}
                style={{
                  height: '16px',
                  width: '16px',
                  backgroundColor: getCategoryColor(c.cat),
                  border: `1px solid ${getCategoryBorder(c.cat)}`,
                  borderRadius: 'var(--ggui-shape-radius-sm, 4px)'
                }}
              />
              <Text variant="caption">{c.label}</Text>
            </Stack>
          ))}
        </Stack>

        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, minmax(45px, 1fr))',
            gap: '6px',
            width: '100%',
            overflowX: 'auto',
            paddingBottom: 'var(--ggui-spacing-4, 16px)'
          }}
        >
          {filteredElements.map((el) => {
            const isSelected = selectedElement?.atomicNumber === el.atomicNumber;
            const isMatch = searchQuery !== '' && 
              (el.name?.toLowerCase().includes(searchQuery.toLowerCase()) || 
               el.symbol?.toLowerCase().includes(searchQuery.toLowerCase()));

            return (
              <button
                key={el.atomicNumber ?? Math.random()}
                onClick={() => setSelectedElement(el)}
                style={{
                  gridColumn: el.col ?? 'auto',
                  gridRow: el.row ?? 'auto',
                  aspectRatio: '1 / 1',
                  padding: '4px',
                  display: 'flex',
                  flexDirection: 'column',
                  alignItems: 'center',
                  justifyContent: 'center',
                  cursor: 'pointer',
                  backgroundColor: getCategoryColor(el.category),
                  border: isSelected 
                    ? `3px solid var(--ggui-color-primary-600, #0284c7)` 
                    : `1px solid ${getCategoryBorder(el.category)}`,
                  borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                  transition: 'all 150ms ease-in-out',
                  opacity: searchQuery === '' || isMatch ? 1 : 0.3,
                  transform: isSelected ? 'scale(1.05)' : 'scale(1)',
                  boxShadow: isSelected ? 'var(--ggui-shape-shadow-md)' : 'none',
                  outline: 'none',
                  position: 'relative'
                }}
              >
                <Text
                  size="xs"
                  weight="bold"
                  style={{
                    position: 'absolute',
                    top: '2px',
                    left: '4px',
                    fontSize: '10px'
                  }}
                >
                  {el.atomicNumber}
                </Text>
                <Text size="lg" weight="bold">
                  {el.symbol}
                </Text>
                <Text
                  size="xs"
                  truncate
                  style={{ fontSize: '9px', marginTop: '2px' }}
                >
                  {el.name}
                </Text>
              </button>
            );
          })}
        </Box>

        {selectedElement && (
          <Card shadow="lg" border radius="xl" padding={24}>
            <Stack direction="horizontal" gap={24} align="center" wrap>
              <Box
                padding={24}
                style={{
                  backgroundColor: getCategoryColor(selectedElement.category),
                  border: `2px solid ${getCategoryBorder(selectedElement.category)}`,
                  borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                  minWidth: '120px',
                  display: 'flex',
                  flexDirection: 'column',
                  alignItems: 'center'
                }}
              >
                <Text size="4xl" weight="bold">
                  {selectedElement.symbol}
                </Text>
                <Text variant="label">#{selectedElement.atomicNumber}</Text>
              </Box>

              <Stack gap={4} style={{ flex: 1 }}>
                <Heading level={2}>{selectedElement.name ?? 'Unknown Element'}</Heading>
                <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {selectedElement.category?.toUpperCase() ?? 'N/A'}
                </Text>

                <Spacer size={8} />
                <Divider />
                <Spacer size={8} />

                <Stack direction="horizontal" gap={32} wrap>
                  <Stack gap={2}>
                    <Text variant="overline">Atomic Weight</Text>
                    <Text weight="semibold" size="lg">
                      {selectedElement.atomicWeight ?? 'N/A'} u
                    </Text>
                  </Stack>
                  <Stack gap={2}>
                    <Text variant="overline">Group Position</Text>
                    <Text weight="semibold" size="lg">
                      Row {selectedElement.row}, Column {selectedElement.col}
                    </Text>
                  </Stack>
                </Stack>
              </Stack>

              <Box style={{ alignSelf: 'start' }}>
                <button
                  onClick={() => setSelectedElement(null)}
                  style={{
                    background: 'none',
                    border: 'none',
                    cursor: 'pointer',
                    color: 'var(--ggui-color-onSurfaceVariant, #52525b)',
                    padding: '4px'
                  }}
                >
                  <Icon name="x" size={24} />
                </button>
              </Box>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Box,
  Text,
  Heading,
  Button,
  Badge,
  Icon,
  Tabs,
  Table,
  Spacer,
  Divider,
} from '@ggui-ai/design/primitives';

interface Spec {
  key: string;
  value: string;
}

interface Review {
  author: string;
  rating: number;
  text: string;
  date: string;
}

interface Props {
  /** Product object with id, name, price, currency, rating, stock, description, specifications[], reviews[] */
  product: {
    id?: string;
    name?: string;
    price?: number;
    currency?: string;
    rating?: number;
    reviewCount?: number;
    stock?: number;
    description?: string;
    specifications?: unknown[];
    reviews?: unknown[];
  };
  /** Callback for adding to cart */
  addToCart?: (payload: { productId: string; quantity: number }) => void;
}

export default function GeneratedComponent({
  product = {
    id: 'prod-001',
    name: 'Wireless Noise-Cancelling Headphones',
    price: 249.99,
    currency: 'USD',
    rating: 4.3,
    reviewCount: 128,
    stock: 12,
    description: 'Premium wireless headphones with adaptive noise cancellation, 30-hour battery life, and ultra-comfortable memory foam ear cushions.',
    specifications: [
      { key: 'Brand', value: 'AudioMax' },
      { key: 'Battery Life', value: '30 hours' },
    ],
    reviews: [
      { author: 'Alex M.', rating: 5, text: 'Best headphones I have ever owned. The noise cancellation is incredible.', date: '2026-03-01' },
    ],
  },
  addToCart,
}: Props) {
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  const stock = product.stock ?? 0;
  const isOutOfStock = stock <= 0;
  const isLowStock = stock > 0 && stock < 5;

  const handleAddToCart = () => {
    addToCart?.({
      productId: product.id ?? '',
      quantity,
    });
  };

  const renderRatingStars = (rating: number = 0) => {
    const stars = [];
    for (let i = 1; i <= 5; i++) {
      stars.push(
        <Icon
          key={i}
          name="check"
          size={16}
          color={i <= Math.round(rating) ? 'var(--ggui-color-warning-500, #f59e0b)' : 'var(--ggui-color-neutral-300, #d1d5db)'}
        />
      );
    }
    return <Stack direction="horizontal" gap={2}>{stars}</Stack>;
  };

  const specifications = (product.specifications || []) as Record<string, unknown>[];
  const reviews = (product.reviews || []) as Review[];

  const tabItems = [
    {
      key: 'description',
      label: 'Description',
      content: (
        <Box paddingY={16}>
          <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">
            {product.description ?? 'No description available.'}
          </Text>
        </Box>
      ),
    },
    {
      key: 'specifications',
      label: 'Specifications',
      content: (
        <Box paddingY={16}>
          <Table
            bordered
            compact
            columns={[
              { key: 'key', header: 'Feature', width: '30%' },
              { key: 'value', header: 'Details' },
            ]}
            data={specifications}
          />
        </Box>
      ),
    },
    {
      key: 'reviews',
      label: 'Reviews',
      content: (
        <Box paddingY={16}>
          <Stack gap={24}>
            {reviews.length > 0 ? (
              reviews.map((review, idx) => (
                <Stack key={idx} gap={8}>
                  <Stack direction="horizontal" justify="between" align="center">
                    <Text weight="semibold">{review.author}</Text>
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{review.date}</Text>
                  </Stack>
                  {renderRatingStars(review.rating)}
                  <Text variant="bodySmall">{review.text}</Text>
                  {idx < reviews.length - 1 && <Divider margin={8} />}
                </Stack>
              ))
            ) : (
              <Text align="center" variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                No reviews yet.
              </Text>
            )}
          </Stack>
        </Box>
      ),
    },
  ];

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-8, 32px) var(--ggui-spacing-4, 16px)">
      <Stack gap={48}>
        {/* Top Section */}
        <Box>
          <Stack direction="horizontal" gap={32} wrap align="start">
            {/* Product Image Placeholder */}
            <Box
              style={{
                flex: '1 1 400px',
                aspectRatio: '1/1',
                backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)',
                borderRadius: 'var(--ggui-shape-radius-xl, 16px)',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                border: '1px solid var(--ggui-color-primary-100, #e0f2fe)',
              }}
            >
              <Stack align="center" gap={12}>
                <Icon name="search" size={48} color="var(--ggui-color-primary-300, #7dd3fc)" />
                <Text weight="medium" color="var(--ggui-color-primary-600, #0284c7)">
                  {product.name ?? 'Product Image'}
                </Text>
              </Stack>
            </Box>

            {/* Product Details */}
            <Stack style={{ flex: '1 1 300px' }} gap={24}>
              <Stack gap={8}>
                {isOutOfStock ? (
                  <Badge variant="error" size="sm">Out of Stock</Badge>
                ) : isLowStock ? (
                  <Badge variant="warning" size="sm">Low Stock</Badge>
                ) : (
                  <Badge variant="success" size="sm">In Stock</Badge>
                )}
                <Heading level={1}>{product.name ?? 'Unknown Product'}</Heading>
                <Stack direction="horizontal" align="center" gap={12}>
                  {renderRatingStars(product.rating)}
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    ({product.reviewCount ?? 0} reviews)
                  </Text>
                </Stack>
              </Stack>

              <Text size="3xl" weight="bold" color="var(--ggui-color-primary-700, #0369a1)">
                {product.currency ?? '$'}{product.price?.toFixed(2) ?? '0.00'}
              </Text>

              <Divider margin={8} />

              <Stack gap={16}>
                <Text variant="label">Quantity</Text>
                <Stack direction="horizontal" align="center" gap={16}>
                  <Stack direction="horizontal" align="center" gap={4}>
                    <Button
                      variant="secondary"
                      size="sm"
                      disabled={quantity <= 1 || isOutOfStock}
                      onClick={() => setQuantity(q => Math.max(1, q - 1))}
                    >
                      <Icon name="minus" size={14} />
                    </Button>
                    <Box
                      style={{
                        minWidth: '40px',
                        textAlign: 'center',
                        padding: '4px 8px',
                        border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                        borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                      }}
                    >
                      <Text weight="medium">{quantity}</Text>
                    </Box>
                    <Button
                      variant="secondary"
                      size="sm"
                      disabled={quantity >= stock || isOutOfStock}
                      onClick={() => setQuantity(q => Math.min(stock, q + 1))}
                    >
                      <Icon name="plus" size={14} />
                    </Button>
                  </Stack>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {stock} available
                  </Text>
                </Stack>

                <Button
                  variant="primary"
                  size="lg"
                  fullWidth
                  disabled={isOutOfStock}
                  leftIcon={<Icon name="check" size={20} />}
                  onClick={handleAddToCart}
                >
                  {isOutOfStock ? 'Currently Unavailable' : 'Add to Cart'}
                </Button>
              </Stack>
            </Stack>
          </Stack>
        </Box>

        {/* Middle Section - Tabs */}
        <Card padding={24} shadow="sm">
          <Tabs
            items={tabItems}
            activeKey={activeTab}
            onChange={setActiveTab}
            variant="line"
          />
        </Card>
      </Stack>
      <Spacer size={40} />
    </Container>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import {
  Stack,
  Text,
  Heading,
  Card,
  Box,
  Button,
  Input,
  Spacer,
  Badge,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Callback to send a message */
  sendMessage?: (payload: { text: string; timestamp: string }) => void;
}

export default function GeneratedComponent(props: Props) {
  const {
    title = 'Team Chat',
    currentUser = 'You',
    participantCount = 0,
    messages = [],
    sendMessage,
  } = props;

  const [inputValue, setInputValue] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom on mount and whenever messages change
  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  // Stream Contract: Listen for agent-data events
  useEffect(() => {
    const handleAgentData = (event: any) => {
      console.log('Received agent data:', event.detail);
    };
    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  const handleSend = () => {
    if (!inputValue.trim()) return;

    const payload = {
      text: inputValue,
      timestamp: new Date().toISOString(),
    };

    sendMessage?.(payload);
    setInputValue('');
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const formatTime = (isoString?: string) => {
    if (!isoString) return '';
    try {
      return new Intl.DateTimeFormat('en-US', {
        hour: 'numeric',
        minute: 'numeric',
        hour12: true,
      }).format(new Date(isoString));
    } catch (e) {
      return '';
    }
  };

  return (
    <Card
      padding={0}
      shadow="lg"
      radius="xl"
      border
      children={
        <Stack gap={0} align="stretch" style={{ height: '600px', maxHeight: '80vh' }}>
          {/* Header */}
          <Box
            padding={16}
            background="var(--ggui-color-surface, #fafafa)"
            style={{ borderBottom: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)' }}
          >
            <Stack direction="horizontal" align="center" justify="between">
              <Stack direction="horizontal" gap={8} align="center">
                <Heading level={4}>{title}</Heading>
                {participantCount > 0 && (
                  <Badge variant="primary" size="sm">
                    {participantCount} participants
                  </Badge>
                )}
              </Stack>
            </Stack>
          </Box>

          {/* Message List */}
          <Box
            padding={16}
            style={{
              flex: 1,
              overflowY: 'auto',
              background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            }}
            ref={scrollRef}
          >
            <Stack gap={12}>
              {messages.map((msg, i) => {
                const isMe = msg.sender === currentUser;
                const showName = i === 0 || messages[i - 1].sender !== msg.sender;
                const time = formatTime(msg.timestamp);

                return (
                  <Stack
                    key={`${msg.timestamp}-${i}`}
                    gap={4}
                    align={isMe ? 'end' : 'start'}
                    style={{ animation: 'ggui-fadeIn 200ms ease-out' }}
                  >
                    {showName && !isMe && (
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                        {msg.sender ?? 'Unknown'}
                      </Text>
                    )}
                    <Stack
                      direction="horizontal"
                      align="end"
                      gap={8}
                      style={{ flexDirection: isMe ? 'row-reverse' : 'row' }}
                    >
                      <Box
                        padding="8px 12px"
                        borderRadius={isMe ? '12px 12px 2px 12px' : '12px 12px 12px 2px'}
                        background={
                          isMe
                            ? 'var(--ggui-color-primary-600, #0284c7)'
                            : 'var(--ggui-color-surface, #ffffff)'
                        }
                        style={{
                          maxWidth: '80%',
                          boxShadow: 'var(--ggui-shape-shadow-sm)',
                        }}
                      >
                        <Text
                          color={isMe ? '#ffffff' : 'var(--ggui-color-onSurface)'}
                          variant="bodySmall"
                        >
                          {msg.text ?? ''}
                        </Text>
                      </Box>
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                        {time}
                      </Text>
                    </Stack>
                  </Stack>
                );
              })}
            </Stack>
          </Box>

          {/* Input Area */}
          <Box
            padding={16}
            background="var(--ggui-color-surface, #fafafa)"
            style={{ borderTop: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)' }}
          >
            <Stack gap={8}>
              <Text as="label" variant="label" color="var(--ggui-color-onSurfaceVariant)" style={{ display: 'none' }} htmlFor="chat-message-input">
                Message
              </Text>
              <Stack direction="horizontal" gap={12} align="end">
                <Box style={{ flex: 1 }}>
                  <Input
                    id="chat-message-input"
                    label="Message"
                    placeholder="Type a message..."
                    value={inputValue}
                    onChange={setInputValue}
                    onKeyDown={handleKeyDown}
                    size="md"
                    style={{ marginBottom: 0 }}
                  />
                </Box>
                <Button
                  variant="primary"
                  disabled={!inputValue.trim()}
                  onClick={handleSend}
                  leftIcon={
                    <svg
                      width="16"
                      height="16"
                      viewBox="0 0 24 24"
                      fill="none"
                      stroke="currentColor"
                      strokeWidth="2"
                    >
                      <path d="M22 2L11 13M22 2l-7 20-4-9-9-4 20-7z" />
                    </svg>
                  }
                >
                  Send
                </Button>
              </Stack>
            </Stack>
          </Box>
        </Stack>
      }
    />
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Stack,
  Card,
  Text,
  Heading,
  Box,
  Spacer,
  Divider,
} from '@ggui-ai/design/primitives';
import { CardGrid } from '@ggui-ai/design/compositions';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<Stock>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

export default function GeneratedComponent(props: Props) {
  const { stocks: initialStocks = [], lastUpdated: initialLastUpdated = '' } = props;

  const [displayData, setDisplayData] = useState<Props>({
    stocks: initialStocks,
    lastUpdated: initialLastUpdated,
  });

  useEffect(() => {
    const handleAgentData = (event: any) => {
      const newData = event.detail as Props;
      if (newData) {
        setDisplayData((prev) => ({
          stocks: newData.stocks ?? prev.stocks,
          lastUpdated: newData.lastUpdated ?? prev.lastUpdated,
        }));
      }
    };

    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  const formatTimestamp = (isoString?: string) => {
    if (!isoString) return 'Connecting...';
    try {
      const date = new Date(isoString);
      return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' });
    } catch {
      return 'Invalid Date';
    }
  };

  return (
    <Box background="var(--ggui-color-surface, #fafafa)" paddingY={32}>
      <Container maxWidth="xl">
        <Stack gap={24}>
          {/* Dashboard Header */}
          <Stack direction="horizontal" align="end" justify="between">
            <Stack gap={4}>
              <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
                Market Watch
              </Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Real-time equity performance monitoring
              </Text>
            </Stack>
            <Stack align="end" gap={0}>
              <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Last Updated
              </Text>
              <Text weight="semibold" color="var(--ggui-color-primary-600, #0284c7)">
                {formatTimestamp(displayData.lastUpdated)}
              </Text>
            </Stack>
          </Stack>

          <Divider margin={8} />

          {/* Stock Grid */}
          <CardGrid columns={{ sm: 1, md: 3 }} gap={24}>
            {displayData.stocks.map((stock, index) => {
              const isPositive = (stock.change ?? 0) >= 0;
              const statusColor = isPositive
                ? 'var(--ggui-color-success-600, #16a34a)'
                : 'var(--ggui-color-error-600, #dc2626)';
              const borderColor = isPositive
                ? 'var(--ggui-color-success-200, #bbf7d0)'
                : 'var(--ggui-color-error-200, #fecaca)';

              return (
                <Card
                  key={stock.symbol ?? index}
                  shadow="sm"
                  padding={20}
                  border={true}
                  radius="lg"
                  // Using inline style for the specific dynamic border color required by the prompt
                  style={{
                    borderLeft: `4px solid ${statusColor}`,
                    borderColor: borderColor,
                    transition: 'transform 0.2s ease-in-out',
                  }}
                >
                  <Stack gap={16}>
                    <Stack direction="horizontal" justify="between" align="start">
                      <Stack gap={0}>
                        <Text size="xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                          {stock.symbol ?? '---'}
                        </Text>
                        <Text
                          variant="caption"
                          truncate
                          color="var(--ggui-color-onSurfaceVariant, #52525b)"
                        >
                          {stock.name ?? 'Unknown Company'}
                        </Text>
                      </Stack>
                      <Box
                        paddingX={8}
                        paddingY={4}
                        borderRadius={4}
                        background={isPositive ? 'var(--ggui-color-success-50)' : 'var(--ggui-color-error-50)'}
                      >
                        <Text weight="bold" size="sm" color={statusColor}>
                          {isPositive ? '▲' : '▼'}
                        </Text>
                      </Box>
                    </Stack>

                    <Stack gap={4}>
                      <Text size="3xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                        ${(stock.price ?? 0).toFixed(2)}
                      </Text>
                      <Stack direction="horizontal" gap={8} align="center">
                        <Text weight="semibold" color={statusColor}>
                          {isPositive ? '+' : ''}
                          {(stock.change ?? 0).toFixed(2)}
                        </Text>
                        <Box
                          width={1}
                          height={12}
                          background="var(--ggui-color-outlineVariant, #e4e4e7)"
                        />
                        <Text weight="semibold" color={statusColor}>
                          {isPositive ? '+' : ''}
                          {(stock.changePercent ?? 0).toFixed(2)}%
                        </Text>
                      </Stack>
                    </Stack>
                  </Stack>
                </Card>
              );
            })}
          </CardGrid>

          {displayData.stocks.length === 0 && (
            <Card padding={48} border={true} shadow="none">
              <Stack align="center" gap={12}>
                <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Waiting for market data stream...
                </Text>
              </Stack>
            </Card>
          )}
        </Stack>
      </Container>
    </Box>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  Select,
  Toggle,
  Progress,
  Container,
  Box,
  Heading,
  Divider,
  Spacer,
  MotionKeyframes,
  useMotion
} from '@ggui-ai/design/primitives';

interface ProfileData {
  name: string;
  email: string;
  avatar: string;
  role: string;
  emailNotifications: boolean;
  theme: string;
}

interface Props {
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Action: Called with all profile data when user completes onboarding */
  onComplete?: (data: ProfileData) => void;
}

export default function GeneratedComponent({
  initialProfile = {},
  avatarOptions = ["👤", "🧑‍💻", "🎨", "📊"],
  roleOptions = ["Developer", "Designer", "Manager", "Other"],
  onComplete
}: Props) {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState<ProfileData>({
    name: initialProfile?.name ?? '',
    email: initialProfile?.email ?? '',
    avatar: initialProfile?.avatar ?? avatarOptions[0] ?? "👤",
    role: initialProfile?.role ?? roleOptions[0] ?? "Developer",
    emailNotifications: initialProfile?.emailNotifications ?? true,
    theme: initialProfile?.theme ?? 'light',
  });

  const { motionEnabled } = useMotion();

  // Simple validation
  const isEmailValid = (email: string) => /^\S+@\S+\.\S+$/.test(email);
  const isStep1Valid = formData.name.trim().length > 0 && isEmailValid(formData.email);

  const handleNext = () => setStep((s) => Math.min(s + 1, 3));
  const handleBack = () => setStep((s) => Math.max(s - 1, 1));
  const handleComplete = () => onComplete?.(formData);

  const stepProgress = (step / 3) * 100;

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-8, 32px)">
      <MotionKeyframes />
      <Card shadow="lg" padding={0} radius="xl" border>
        {/* Header / Progress Section */}
        <Box padding={24} background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius="16px 16px 0 0">
          <Stack gap={16}>
            <Stack direction="horizontal" justify="between" align="center">
              <Heading level={4} color="var(--ggui-color-onSurface, #18181b)">
                Onboarding Wizard
              </Heading>
              <Badge step={step} />
            </Stack>
            <Progress value={stepProgress} max={100} variant="primary" size="sm" />
          </Stack>
        </Box>

        <Box padding={32} style={{ animation: motionEnabled ? 'ggui-fadeIn 200ms ease-out' : 'none' }}>
          {step === 1 && (
            <Stack gap={24}>
              <Stack gap={4}>
                <Heading level={3}>Profile Setup</Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Tell us a bit about yourself to get started.
                </Text>
              </Stack>

              <Input
                label="Full Name"
                placeholder="Enter your name"
                required
                value={formData.name}
                onChange={(val) => setFormData(prev => ({ ...prev, name: val }))}
              />

              <Input
                label="Email Address"
                placeholder="you@example.com"
                type="email"
                required
                error={formData.email && !isEmailValid(formData.email) ? "Invalid email format" : undefined}
                value={formData.email}
                onChange={(val) => setFormData(prev => ({ ...prev, email: val }))}
              />

              <Stack gap={8}>
                <Text variant="label">Choose an Avatar</Text>
                <Stack direction="horizontal" gap={12} wrap>
                  {avatarOptions.map((emoji) => (
                    <AvatarButton
                      key={emoji}
                      emoji={emoji}
                      isSelected={formData.avatar === emoji}
                      onSelect={() => setFormData(prev => ({ ...prev, avatar: emoji }))}
                    />
                  ))}
                </Stack>
              </Stack>
            </Stack>
          )}

          {step === 2 && (
            <Stack gap={24}>
              <Stack gap={4}>
                <Heading level={3}>Preferences</Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Customize your workspace experience.
                </Text>
              </Stack>

              <Select
                label="Primary Role"
                value={formData.role}
                onChange={(val) => setFormData(prev => ({ ...prev, role: val }))}
                options={roleOptions.map(r => ({ label: r, value: r }))}
              />

              <Divider margin={8} />

              <Toggle
                label="Enable Email Notifications"
                checked={formData.emailNotifications}
                onChange={(checked) => setFormData(prev => ({ ...prev, emailNotifications: checked }))}
              />

              <Stack gap={8}>
                <Text variant="label">Theme Preference</Text>
                <Stack direction="horizontal" gap={16} align="center">
                  <Text variant="bodySmall">Light</Text>
                  <Toggle
                    label="Dark Mode"
                    checked={formData.theme === 'dark'}
                    onChange={(checked) => setFormData(prev => ({ ...prev, theme: checked ? 'dark' : 'light' }))}
                  />
                  <Text variant="bodySmall">Dark</Text>
                </Stack>
              </Stack>
            </Stack>
          )}

          {step === 3 && (
            <Stack gap={24}>
              <Stack gap={4}>
                <Heading level={3}>Review & Confirm</Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Please review your selections before finishing.
                </Text>
              </Stack>

              <Box padding={20} background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius={12}>
                <Stack gap={16}>
                  <Stack direction="horizontal" align="center" gap={16}>
                    <Box 
                      background="var(--ggui-color-container, #ede9fe)" 
                      borderRadius={50} 
                      padding={12}
                      style={{ fontSize: '32px' }}
                    >
                      {formData.avatar}
                    </Box>
                    <Stack gap={0}>
                      <Text weight="bold" size="lg">{formData.name}</Text>
                      <Text variant="caption">{formData.email}</Text>
                    </Stack>
                  </Stack>

                  <Divider margin={8} />

                  <Stack gap={8}>
                    <SummaryRow label="Role" value={formData.role} />
                    <SummaryRow label="Notifications" value={formData.emailNotifications ? "Enabled" : "Disabled"} />
                    <SummaryRow label="Default Theme" value={formData.theme === 'dark' ? "Dark" : "Light"} />
                  </Stack>
                </Stack>
              </Box>
            </Stack>
          )}

          <Spacer size={40} />

          {/* Footer Controls */}
          <Stack direction="horizontal" justify="between">
            <Button
              variant="ghost"
              disabled={step === 1}
              onClick={handleBack}
            >
              Back
            </Button>

            {step < 3 ? (
              <Button
                variant="primary"
                disabled={step === 1 && !isStep1Valid}
                onClick={handleNext}
              >
                Next Step
              </Button>
            ) : (
              <Button variant="primary" onClick={handleComplete}>
                Complete Setup
              </Button>
            )}
          </Stack>
        </Box>
      </Card>
    </Container>
  );
}

function Badge({ step }: { step: number }) {
  return (
    <Box
      paddingX={12}
      paddingY={4}
      background="var(--ggui-color-primary-600, #0284c7)"
      borderRadius={100}
    >
      <Text color="white" weight="bold" size="xs">Step {step} of 3</Text>
    </Box>
  );
}

function AvatarButton({ emoji, isSelected, onSelect }: { emoji: string, isSelected: boolean, onSelect: () => void }) {
  return (
    <button
      onClick={onSelect}
      style={{
        width: '56px',
        height: '56px',
        fontSize: '24px',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
        cursor: 'pointer',
        border: isSelected 
          ? '2px solid var(--ggui-color-primary-600, #0284c7)' 
          : '2px solid var(--ggui-color-outline, #d4d4d8)',
        background: isSelected 
          ? 'var(--ggui-color-primary-50, #f0f9ff)' 
          : 'var(--ggui-color-surface, #fafafa)',
        transition: 'all 200ms ease-in-out',
        outline: 'none'
      }}
    >
      {emoji}
    </button>
  );
}

function SummaryRow({ label, value }: { label: string, value: string }) {
  return (
    <Stack direction="horizontal" justify="between">
      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">{label}</Text>
      <Text variant="bodySmall" weight="medium">{value}</Text>
    </Stack>
  );
}

