import React, { useState, useMemo } from 'react';
import { Card, Stack, Text, Heading, Button, Input, TextArea, RadioGroup, Checkbox, Progress, Divider, Box } from '@ggui-ai/design/primitives';

interface Props {
  featureOptions?: string[];
  satisfactionLabels?: string[];
  onSubmit?: (data: any) => void;
}

export default function GeneratedComponent({
  featureOptions = ["Dashboard Analytics", "Team Collaboration", "API Integration", "Custom Workflows", "Mobile App", "AI Assistance"],
  satisfactionLabels = ["Very Unsatisfied", "Unsatisfied", "Neutral", "Satisfied", "Very Satisfied"],
  onSubmit
}: Props) {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: 3,
    features: [] as string[],
    comments: ''
  });

  const [touched, setTouched] = useState({ name: false, email: false });

  const validateEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const errors = useMemo(() => ({
    name: touched.name && !formData.name ? 'Name is required' : '',
    email: touched.email && !validateEmail(formData.email) ? 'Valid email is required' : ''
  }), [formData.name, formData.email, touched]);

  const isStepValid = useMemo(() => {
    if (step === 1) return !!formData.name && validateEmail(formData.email);
    return true;
  }, [step, formData.name, formData.email]);

  const updateField = (field: string, value: any) => {
    setFormData(prev => ({ ...prev, [field]: value }));
    setTouched(prev => ({ ...prev, [field]: true }));
  };

  const handleNext = () => setStep((s) => Math.min(s + 1, 5));
  const handleBack = () => setStep((s) => Math.max(s - 1, 1));

  const totalSteps = 4;

  return (
    <Card padding={24} shadow="md">
      <Stack gap={16}>
        <div role="region" aria-live="polite">
          <Stack direction="horizontal" justify="between" align="center">
            <Heading level={3}>Step {Math.min(step, totalSteps)} of {totalSteps}</Heading>
            <Progress value={(Math.min(step, totalSteps) / totalSteps) * 100} size="sm" />
          </Stack>
        </div>

        <Divider />

        <div role="tabpanel" aria-labelledby={`step-${step}`}>
          {step === 1 && (
            <Stack gap={16}>
              <Heading level={4}>Personal Details</Heading>
              <Input label="Name" required value={formData.name} onChange={(v) => updateField('name', v)} error={errors.name} />
              <Input label="Email" required type="email" value={formData.email} onChange={(v) => updateField('email', v)} error={errors.email} />
            </Stack>
          )}

          {step === 2 && (
            <Stack gap={16}>
              <Heading level={4}>How satisfied are you?</Heading>
              <RadioGroup
                label="Satisfaction Rating"
                value={formData.satisfaction.toString()}
                onChange={(v) => updateField('satisfaction', parseInt(v))}
                options={satisfactionLabels.map((label, i) => ({ value: (i + 1).toString(), label }))}
              />
            </Stack>
          )}

          {step === 3 && (
            <Stack gap={16}>
              <Heading level={4}>Features of Interest</Heading>
              {featureOptions.map(f => (
                <Checkbox key={f} label={f} checked={formData.features.includes(f)} onChange={() => {
                  const newFeatures = formData.features.includes(f) 
                    ? formData.features.filter(x => x !== f) 
                    : [...formData.features, f];
                  updateField('features', newFeatures);
                }} />
              ))}
            </Stack>
          )}

          {step === 4 && (
            <Stack gap={16}>
              <Heading level={4}>Additional Comments</Heading>
              <TextArea
                label="Comments"
                value={formData.comments}
                onChange={(v) => updateField('comments', v)}
                maxLength={500}
                showCount
                rows={4}
              />
            </Stack>
          )}

          {step === 5 && (
            <Stack gap={16}>
              <Heading level={4}>Review Your Answers</Heading>
              <Box background="var(--ggui-color-surfaceVariant)" padding={16} borderRadius={8}>
                <dl style={{ margin: 0 }}>
                  {[
                    { label: 'Name', value: formData.name },
                    { label: 'Email', value: formData.email },
                    { label: 'Satisfaction', value: formData.satisfaction },
                    { label: 'Features', value: formData.features.join(', ') || 'None' },
                    { label: 'Comments', value: formData.comments || 'None' }
                  ].map(item => (
                    <div key={item.label} style={{ marginBottom: '8px' }}>
                      <dt style={{ fontWeight: 'bold', fontSize: 'var(--ggui-font-size-sm)' }}>{item.label}:</dt>
                      <dd style={{ margin: 0, fontSize: 'var(--ggui-font-size-sm)' }}>{item.value}</dd>
                    </div>
                  ))}
                </dl>
              </Box>
            </Stack>
          )}
        </div>

        <Stack direction="horizontal" gap={8} justify="end">
          {step > 1 && <Button variant="secondary" onClick={handleBack}>Back</Button>}
          {step <= totalSteps ? (
            <Button variant="primary" onClick={handleNext} disabled={!isStepValid}>
              {step === totalSteps ? 'Review' : 'Next'}
            </Button>
          ) : (
            <Button variant="primary" onClick={() => onSubmit?.(formData)}>Submit Survey</Button>
          )}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState } from 'react';
import { 
  Container, 
  Stack, 
  Card, 
  Text, 
  Heading, 
  Button, 
  Badge, 
  Avatar, 
  Divider, 
  Input, 
  Select, 
  Box 
} from '@ggui-ai/design/primitives';

interface Props {
  tasks: Array<{ 
    id?: string; 
    title?: string; 
    priority?: 'low' | 'medium' | 'high'; 
    assignee?: string; 
    column?: string; 
    dueDate?: string 
  }>;
  columns: Array<{ id?: string; name?: string }>;
  onTaskUpdate?: (payload: { action: 'move' | 'edit' | 'create', taskId?: string, data: any }) => void;
}

export default function GeneratedComponent(props: Props) {
  const { tasks: initialTasks = [], columns = [], onTaskUpdate } = props;
  const [tasks, setTasks] = useState(initialTasks);
  const [addingToColumn, setAddingToColumn] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const totalTasks = tasks.length;
  const completedTasks = tasks.filter(t => t.column === 'done').length;

  const handleMove = (taskId: string, targetColumn: string) => {
    const newTasks = tasks.map(t => t.id === taskId ? { ...t, column: targetColumn } : t);
    setTasks(newTasks);
    onTaskUpdate?.({ action: 'move', taskId, data: { column: targetColumn } });
  };

  const handleAddTask = (columnId: string) => {
    if (!newTaskTitle) return;
    const newTask = {
      id: Math.random().toString(36).substring(2, 9),
      title: newTaskTitle,
      priority: newTaskPriority,
      column: columnId,
      assignee: '??'
    };
    setTasks([...tasks, newTask]);
    onTaskUpdate?.({ action: 'create', data: newTask });
    setAddingToColumn(null);
    setNewTaskTitle('');
  };

  const getPriorityVariant = (p: string) => {
    if (p === 'high') return 'error';
    if (p === 'medium') return 'warning';
    return 'info';
  };

  return (
    <Container maxWidth="full" padding={24}>
      <Stack gap={16} style={{ marginBottom: '24px' }}>
        <Heading level={2}>Project Board</Heading>
        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
          {completedTasks} of {totalTasks} tasks completed
        </Text>
      </Stack>

      <Stack direction="horizontal" gap={24} align="start" wrap>
        {columns.map(col => (
          <Box 
            key={col.id} 
            padding={16} 
            background="var(--ggui-color-surfaceVariant)" 
            borderRadius={8} 
            style={{ width: 320 }}
          >
            <Stack gap={12}>
              <Stack direction="horizontal" justify="between" align="center">
                <Heading level={4}>{col.name}</Heading>
                <Badge variant="secondary">{tasks.filter(t => t.column === col.id).length}</Badge>
              </Stack>
              <Divider />
              {tasks.filter(t => t.column === col.id).map(task => (
                <Card key={task.id} padding={12} shadow="sm">
                  <Stack gap={8}>
                    <Text variant="label">{task.title}</Text>
                    <Stack direction="horizontal" justify="between" align="center">
                      <Badge variant={getPriorityVariant(task.priority || 'low') as any}>
                        {task.priority}
                      </Badge>
                      <Avatar name={task.assignee || '??'} size={24} />
                    </Stack>
                    <Select 
                      value={task.column ?? ''} 
                      onChange={(v) => handleMove(task.id!, v)}
                      options={columns.map(c => ({ label: c.name!, value: c.id! }))}
                      size="sm"
                    />
                  </Stack>
                </Card>
              ))}
              {addingToColumn === col.id ? (
                <Stack gap={8}>
                  <Input 
                    value={newTaskTitle} 
                    onChange={setNewTaskTitle} 
                    placeholder="Task title..." 
                    size="sm"
                  />
                  <Select 
                    value={newTaskPriority} 
                    onChange={(v: any) => setNewTaskPriority(v)} 
                    options={[
                      { label: 'Low', value: 'low' }, 
                      { label: 'Medium', value: 'medium' }, 
                      { label: 'High', value: 'high' }
                    ]} 
                    size="sm"
                  />
                  <Button onClick={() => handleAddTask(col.id!)} size="sm">Save</Button>
                </Stack>
              ) : (
                <Button variant="ghost" onClick={() => setAddingToColumn(col.id!)} size="sm">+ Add Task</Button>
              )}
            </Stack>
          </Box>
        ))}
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import { Card, Stack, Text, Heading, Input, Box, Divider } from '@ggui-ai/design/primitives';

interface Element {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  /** Full periodic table element data */
  elements: Array<Element>;
}

const CATEGORY_COLORS: Record<string, string> = {
  'nonmetal': 'var(--ggui-color-primary-200, #bae6fd)',
  'noble-gas': 'var(--ggui-color-success-200, #bbf7d0)',
  'alkali-metal': 'var(--ggui-color-warning-200, #fde68a)',
  'alkaline-earth': 'var(--ggui-color-info-200, #a5f3fc)',
  'transition-metal': 'var(--ggui-color-primary-100, #e0f2fe)',
  'halogen': 'var(--ggui-color-error-100, #fee2e2)',
  'metalloid': 'var(--ggui-color-neutral-200, #e5e7eb)',
  'lanthanoid': 'var(--ggui-color-neutral-300, #d1d5db)',
  'actinoid': 'var(--ggui-color-neutral-400, #9ca3af)',
};

export default function GeneratedComponent(props: Props) {
  const { elements = [] } = props;
  const [search, setSearch] = useState('');
  const [selected, setSelected] = useState<Element | null>(null);

  const filteredElements = elements.filter(
    (el) =>
      el.name?.toLowerCase().includes(search.toLowerCase()) ||
      el.symbol?.toLowerCase().includes(search.toLowerCase())
  );

  const categories = Array.from(new Set(elements.map((e) => e.category || 'unknown')));

  return (
    <Stack gap={24} padding={24}>
      <Stack gap={16} align="center">
        <Heading level={1}>Periodic Table</Heading>
        <Box style={{ width: '100%', maxWidth: '400px' }}>
          <label htmlFor="search-elements" style={{ display: 'none' }}>Search Elements</label>
          <Input 
            id="search-elements"
            label="Search Elements"
            placeholder="Search by name or symbol..." 
            value={search} 
            onChange={setSearch} 
            type="search"
          />
        </Box>
      </Stack>

      <div style={{
        display: 'grid',
        gridTemplateColumns: 'repeat(18, 1fr)',
        gap: '4px',
        maxWidth: '1200px',
        margin: '0 auto',
        width: '100%'
      }}>
        {filteredElements.map((el) => (
          <div
            key={el.atomicNumber}
            onClick={() => setSelected(el)}
            style={{
              gridRow: el.row,
              gridColumn: el.col,
              aspectRatio: '1',
              backgroundColor: el.category ? (CATEGORY_COLORS[el.category] || 'var(--ggui-color-neutral-100)') : 'var(--ggui-color-neutral-100)',
              borderRadius: 'var(--ggui-shape-radius-sm)',
              padding: '4px',
              cursor: 'pointer',
              display: 'flex',
              flexDirection: 'column',
              justifyContent: 'space-between',
              border: selected?.atomicNumber === el.atomicNumber 
                ? '2px solid var(--ggui-color-primary-600)' 
                : '1px solid var(--ggui-color-neutral-200)'
            }}
          >
            <Text variant="caption">{el.atomicNumber}</Text>
            <Text variant="bodyLarge" style={{ textAlign: 'center', fontWeight: 'bold' }}>{el.symbol}</Text>
          </div>
        ))}
      </div>

      <Stack direction="horizontal" gap={16} justify="center" wrap>
        {categories.map(cat => (
          <Stack direction="horizontal" gap={8} key={cat} align="center">
            <Box style={{ width: 12, height: 12, backgroundColor: CATEGORY_COLORS[cat] || 'var(--ggui-color-neutral-100)', borderRadius: 2 }} />
            <Text variant="caption">{cat}</Text>
          </Stack>
        ))}
      </Stack>

      {selected && (
        <Card shadow="md" padding={24}>
          <Stack gap={8}>
            <Heading level={3}>{selected.name} ({selected.symbol})</Heading>
            <Divider />
            <Text>Atomic Number: {selected.atomicNumber}</Text>
            <Text>Atomic Weight: {selected.atomicWeight}</Text>
            <Text>Category: {selected.category}</Text>
          </Stack>
        </Card>
      )}
    </Stack>
  );
}

import React, { useState } from 'react';
import { 
  Container, 
  Card, 
  Stack, 
  Text, 
  Heading, 
  Button, 
  Badge, 
  Divider, 
  Tabs, 
  Box, 
  Icon,
  Table
} from '@ggui-ai/design/primitives';

interface Props {
  product?: { 
    id?: string; 
    name?: string; 
    price?: number; 
    currency?: string; 
    rating?: number; 
    reviewCount?: number; 
    stock?: number; 
    description?: string; 
    specifications?: { key: string; value: string }[]; 
    reviews?: { author: string; rating: number; text: string; date: string }[];
  };
  onAddToCart?: (payload: { productId: string; quantity: number }) => void;
}

export default function GeneratedComponent(props: Props) {
  const { 
    product = { 
      id: 'prod-001', 
      name: 'Product Name', 
      price: 0, 
      currency: 'USD', 
      rating: 0, 
      reviewCount: 0, 
      stock: 0, 
      description: '', 
      specifications: [], 
      reviews: [] 
    },
    onAddToCart 
  } = props;

  const [quantity, setQuantity] = useState(1);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const {
    id = 'prod-000',
    name = 'Unknown Product',
    price = 0,
    currency = 'USD',
    rating = 0,
    reviewCount = 0,
    stock = 0,
    description = '',
    specifications = [],
    reviews = []
  } = product;

  const isOutOfStock = stock <= 0;

  const handleAddToCart = async () => {
    if (!onAddToCart) return;
    setIsSubmitting(true);
    try {
      await onAddToCart({ productId: id, quantity });
    } finally {
      setIsSubmitting(false);
    }
  };

  const renderStars = (rating: number) => (
    <Stack direction="horizontal" gap={4} align="center">
      {[...Array(5)].map((_, i) => (
        <Icon 
          key={i} 
          name="star" 
          size={16} 
          color={i < Math.round(rating) ? 'var(--ggui-color-warning-500, #f59e0b)' : 'var(--ggui-color-neutral-300, #d1d5db)'} 
        />
      ))}
      <Text variant="caption">{reviewCount} reviews</Text>
    </Stack>
  );

  return (
    <Container maxWidth="lg" padding={24}>
      <article>
        <Stack gap={32}>
          <Stack direction="horizontal" gap={32} wrap>
            <Box 
              padding={64} 
              background="var(--ggui-color-surfaceVariant, #f4f4f5)" 
              borderRadius={12}
            >
              <Text weight="semibold" align="center">{name}</Text>
            </Box>

            <Stack gap={16} style={{ flex: 1 }}>
              <Heading level={1}>{name}</Heading>
              <Text variant="bodyLarge" weight="bold">
                {new Intl.NumberFormat('en-US', { style: 'currency', currency }).format(price)}
              </Text>
              {renderStars(rating)}
              <Box>
                <Badge variant={stock > 0 ? (stock < 5 ? 'warning' : 'success') : 'error'}>
                  {stock > 0 ? (stock < 5 ? `Low Stock (${stock})` : 'In Stock') : 'Out of Stock'}
                </Badge>
              </Box>

              <Divider />

              <Stack direction="horizontal" gap={12} align="center">
                <Button 
                  variant="secondary" 
                  aria-label="Decrease quantity"
                  onClick={() => setQuantity(Math.max(1, quantity - 1))}
                  disabled={isOutOfStock || quantity <= 1}
                >
                  <Icon name="minus" size={16} />
                </Button>
                <Text aria-live="polite" weight="medium">{quantity}</Text>
                <Button 
                  variant="secondary" 
                  aria-label="Increase quantity"
                  onClick={() => setQuantity(Math.min(stock, quantity + 1))}
                  disabled={isOutOfStock || quantity >= stock}
                >
                  <Icon name="plus" size={16} />
                </Button>
                <Button 
                  variant="primary" 
                  onClick={handleAddToCart}
                  disabled={isOutOfStock || isSubmitting}
                  loading={isSubmitting}
                >
                  Add to Cart
                </Button>
              </Stack>
            </Stack>
          </Stack>

          <Tabs
            variant="line"
            items={[
              {
                key: 'description',
                label: 'Description',
                content: <Text variant="body">{description}</Text>
              },
              {
                key: 'specs',
                label: 'Specifications',
                content: (
                  <Table
                    columns={[
                      { key: 'key', header: 'Feature' },
                      { key: 'value', header: 'Detail' }
                    ]}
                    data={specifications as any[]}
                  />
                )
              },
              {
                key: 'reviews',
                label: 'Reviews',
                content: (
                  <Stack gap={16}>
                    {reviews.map((review: any, i: number) => (
                      <Card key={i} padding={16} border={true}>
                        <Stack gap={4}>
                          <Stack direction="horizontal" justify="between">
                            <Text weight="medium">{review.author}</Text>
                            <Text variant="caption">{review.date}</Text>
                          </Stack>
                          <Text variant="bodySmall">{review.text}</Text>
                        </Stack>
                      </Card>
                    ))}
                  </Stack>
                )
              }
            ]}
          />
        </Stack>
      </article>
    </Container>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { Card, Stack, Text, Box, Input, Button, Badge } from '@ggui-ai/design/primitives';

interface Message {
  sender?: string;
  text?: string;
  timestamp?: string;
}

interface Props {
  title: string;
  currentUser: string;
  participantCount?: number;
  messages: Message[];
  onSendMessage: (payload: { text: string; timestamp: string }) => void;
}

export default function GeneratedComponent(props: Props) {
  const { 
    title = 'Chat Window', 
    currentUser = 'You', 
    participantCount, 
    messages = [], 
    onSendMessage 
  } = props;

  const [inputValue, setInputValue] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleData = (e: any) => {
      // Stream Contract implementation: listen for 'ggui:agent-data'
      console.log('Received agent data:', e.detail);
    };
    window.addEventListener('ggui:agent-data', handleData);
    return () => window.removeEventListener('ggui:agent-data', handleData);
  }, []);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = () => {
    if (!inputValue.trim()) return;
    onSendMessage({
      text: inputValue,
      timestamp: new Date().toISOString(),
    });
    setInputValue('');
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <Card padding={0} shadow="md" style={{ display: 'flex', flexDirection: 'column', height: '500px', width: '100%' }}>
      <Box paddingX={16} paddingY={12} style={{ borderBottom: '1px solid var(--ggui-color-outline, #d4d4d8)', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
        <Text variant="label">{title}</Text>
        {participantCount !== undefined && <Badge variant="secondary">{participantCount} participants</Badge>}
      </Box>

      <Box ref={scrollRef} padding={16} style={{ flex: 1, overflowY: 'auto', display: 'flex', flexDirection: 'column', gap: '8px' }}>
        {messages.map((msg, i) => {
          const isMe = msg.sender === currentUser || msg.sender === 'You';
          const showSender = i === 0 || messages[i - 1].sender !== msg.sender;

          return (
            <Stack key={i} align={isMe ? 'end' : 'start'} gap={4}>
              {showSender && <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{msg.sender}</Text>}
              <Box 
                paddingX={12} 
                paddingY={8} 
                borderRadius={12} 
                background={isMe ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)'}
              >
                <Text color={isMe ? '#ffffff' : 'var(--ggui-color-onSurface, #111827)'}>{msg.text}</Text>
              </Box>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {new Date(msg.timestamp || '').toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
              </Text>
            </Stack>
          );
        })}
      </Box>

      <Box padding={16} style={{ borderTop: '1px solid var(--ggui-color-outline, #d4d4d8)' }}>
        <Stack direction="horizontal" gap={8}>
          <Box style={{ flex: 1 }}>
            <Input 
              label="Message"
              value={inputValue} 
              onChange={setInputValue} 
              placeholder="Type a message..." 
              onKeyDown={handleKeyDown}
            />
          </Box>
          <Button onClick={handleSend} disabled={!inputValue.trim()}>Send</Button>
        </Stack>
      </Box>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import { Card, Stack, Text, Heading, Container, Box, Divider } from '@ggui-ai/design/primitives';

interface Props {
  stocks?: Array<{ 
    symbol?: string; 
    name?: string; 
    price?: number; 
    change?: number; 
    changePercent?: number 
  }>;
  lastUpdated?: string;
}

export default function GeneratedComponent(props: Props) {
  const [tickerData, setTickerData] = useState(props.stocks ?? []);
  const [updatedAt, setUpdatedAt] = useState(props.lastUpdated);

  useEffect(() => {
    const handleData = (event: any) => {
      if (event.detail && Array.isArray(event.detail.stocks)) {
        setTickerData(event.detail.stocks);
      }
      if (event.detail && event.detail.lastUpdated) {
        setUpdatedAt(event.detail.lastUpdated);
      }
    };

    window.addEventListener('ggui:agent-data' as any, handleData);
    return () => window.removeEventListener('ggui:agent-data' as any, handleData);
  }, []);

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={24}>
        <Stack direction="horizontal" justify="between" align="center">
          <Heading level={2}>Market Watch</Heading>
          {updatedAt && (
            <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
              Last Updated: {new Date(updatedAt).toLocaleTimeString()}
            </Text>
          )}
        </Stack>

        <Box style={{ 
          display: 'grid', 
          gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', 
          gap: 'var(--ggui-spacing-4, 16px)' 
        }}>
          {tickerData.map((stock, index) => {
            const isPositive = (stock.change ?? 0) >= 0;
            const color = isPositive 
              ? 'var(--ggui-color-success-600, #16a34a)' 
              : 'var(--ggui-color-error-600, #dc2626)';

            return (
              <Card 
                key={stock.symbol ?? index} 
                border={true} 
                shadow="sm" 
                padding={20}
              >
                <Stack gap={8}>
                  <Stack direction="horizontal" justify="between" align="start">
                    <Stack gap={0}>
                      <Heading level={4}>{stock.symbol ?? 'N/A'}</Heading>
                      <Text variant="bodySmall" color="var(--ggui-color-neutral-500, #6b7280)">
                        {stock.name ?? 'Unknown Company'}
                      </Text>
                    </Stack>
                    <Heading level={3}>${stock.price?.toFixed(2) ?? '0.00'}</Heading>
                  </Stack>

                  <Divider margin={8} />

                  <Text 
                    variant="label" 
                    color={color}
                    style={{ display: 'flex', alignItems: 'center', gap: '4px' }}
                  >
                    {isPositive ? '▲' : '▼'} 
                    {Math.abs(stock.change ?? 0).toFixed(2)} ({Math.abs(stock.changePercent ?? 0).toFixed(2)}%)
                  </Text>
                </Stack>
              </Card>
            );
          })}
        </Box>
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import { Card, Stack, Text, Heading, Button, Input, Select, Checkbox, Toggle, Container } from '@ggui-ai/design/primitives';

interface Props {
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: { 
    name?: string; 
    email?: string; 
    avatar?: string; 
    role?: string; 
    emailNotifications?: boolean; 
    theme?: string 
  };
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Callback on final submit */
  onComplete?: (data: any) => void;
}

export default function GeneratedComponent(props: Props) {
  const {
    initialProfile = {},
    avatarOptions = ["👤", "🧑‍💻", "🎨", "📊"],
    roleOptions = ["Developer", "Designer", "Manager", "Other"],
    onComplete,
  } = props;

  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: initialProfile.name ?? '',
    email: initialProfile.email ?? '',
    avatar: initialProfile.avatar ?? avatarOptions[0],
    role: initialProfile.role ?? roleOptions[0],
    emailNotifications: initialProfile.emailNotifications ?? true,
    theme: initialProfile.theme ?? 'light',
  });

  const validateEmail = (email: string) => /\S+@\S+\.\S+/.test(email);
  const isStep1Valid = formData.name.trim() !== '' && validateEmail(formData.email);

  const next = () => setStep((s) => Math.min(s + 1, 3));
  const back = () => setStep((s) => Math.max(s - 1, 1));

  const renderStep = () => {
    switch (step) {
      case 1:
        return (
          <Stack gap={16}>
            <Heading level={3}>Profile Setup</Heading>
            <Input 
              label="Name" 
              required 
              value={formData.name} 
              onChange={(v) => setFormData({ ...formData, name: v })} 
            />
            <Input 
              label="Email" 
              type="email" 
              required 
              value={formData.email} 
              onChange={(v) => setFormData({ ...formData, email: v })} 
              error={formData.email && !validateEmail(formData.email) ? 'Invalid email format' : undefined} 
            />
            <Text variant="label">Choose Avatar</Text>
            <Stack direction="horizontal" gap={8}>
              {avatarOptions.map((a) => (
                <Button 
                  key={a} 
                  variant={formData.avatar === a ? 'primary' : 'outline'} 
                  size="sm" 
                  onClick={() => setFormData({ ...formData, avatar: a })}
                >
                  {a}
                </Button>
              ))}
            </Stack>
          </Stack>
        );
      case 2:
        return (
          <Stack gap={16}>
            <Heading level={3}>Preferences</Heading>
            <Select 
              label="Role" 
              value={formData.role} 
              onChange={(v) => setFormData({ ...formData, role: v })} 
              options={roleOptions.map(r => ({ value: r, label: r }))} 
            />
            <Checkbox 
              label="Email Notifications" 
              checked={formData.emailNotifications} 
              onChange={(v) => setFormData({ ...formData, emailNotifications: v })} 
            />
            <Toggle 
              label={`Theme: ${formData.theme}`} 
              checked={formData.theme === 'dark'} 
              onChange={(v) => setFormData({ ...formData, theme: v ? 'dark' : 'light' })} 
            />
          </Stack>
        );
      case 3:
        return (
          <Stack gap={16}>
            <Heading level={3}>Review & Confirm</Heading>
            <Card padding={16} border={true}>
              <Stack gap={8}>
                <Text variant="bodySmall">Name: {formData.name}</Text>
                <Text variant="bodySmall">Email: {formData.email}</Text>
                <Text variant="bodySmall">Avatar: {formData.avatar}</Text>
                <Text variant="bodySmall">Role: {formData.role}</Text>
                <Text variant="bodySmall">Notifications: {formData.emailNotifications ? 'On' : 'Off'}</Text>
                <Text variant="bodySmall">Theme: {formData.theme}</Text>
              </Stack>
            </Card>
          </Stack>
        );
      default:
        return null;
    }
  };

  return (
    <Container maxWidth="sm">
      <Card padding={24}>
        <Stack gap={24}>
          <Stack gap={8}>
            <Text variant="overline">Step {step} of 3</Text>
            <div style={{ height: 8, background: 'var(--ggui-color-neutral-200)', borderRadius: 4 }}>
              <div 
                style={{ 
                  height: '100%', 
                  width: `${(step / 3) * 100}%`, 
                  background: 'var(--ggui-color-primary-600)', 
                  borderRadius: 4, 
                  transition: 'width 0.3s' 
                }} 
              />
            </div>
          </Stack>

          {renderStep()}

          <Stack direction="horizontal" justify="between">
            <Button variant="secondary" onClick={back} disabled={step === 1}>Back</Button>
            {step < 3 ? (
              <Button 
                variant="primary" 
                onClick={next} 
                disabled={step === 1 && !isStep1Valid}
              >
                Next
              </Button>
            ) : (
              <Button variant="primary" onClick={() => onComplete?.(formData)}>Complete Setup</Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}
